  mutationFn: (newTitle: string) =>
    api.patch(`/snippets/${id}`, { title: newTitle }),

  onMutate: async (newTitle) => {
    await queryClient.cancelQueries({ queryKey: ['snippet', id] });
    const previous = queryClient.getQueryData(['snippet', id]);
    queryClient.setQueryData(['snippet', id], (old: Snippet) => ({
      ...old,
      title: newTitle,
    }));
    return { previous };
  },

  onError: (_err, _vars, context) => {
    queryClient.setQueryData(['snippet', id], context?.previous);
  },

  onSettled: () => {
    queryClient.invalidateQueries({ queryKey: ['snippet', id] });
  },
});

