import { useEffect, useState } from 'react';
import { supabase } from '@/lib/supabase';

function useLiveSnippets(userId: string) {
  const [snippets, setSnippets] = useState<Snippet[]>([]);

  useEffect(() => {
    const channel = supabase
      .channel('snippets-changes')
      .on(
        'postgres_changes',
        { event: '*', schema: 'public', table: 'snippets', filter: `user_id=eq.${userId}` },
        (payload) => {
          if (payload.eventType === 'INSERT') setSnippets(prev => [...prev, payload.new as Snippet]);
          if (payload.eventType === 'DELETE') setSnippets(prev => prev.filter(s => s.id !== payload.old.id));
        }
      )
      .subscribe();

    return () => { supabase.removeChannel(channel); };
  }, [userId]);

  return snippets;
}
